@typeparam TItem
@implements IAsyncDisposable

<div class="infinite-scroll-container" style="overflow-y: auto; max-height: @MaxHeight;">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="_sentinelRef" class="infinite-scroll-sentinel">
            @if (_isLoading)
            {
                <div class="d-flex justify-content-center py-3">
                    <div class="spinner-border text-secondary" role="status">
                        <span class="visually-hidden">Loading...</span>
                    </div>
                </div>
            }
        </div>
    }
</div>

using Microsoft.AspNetCore.Components;
using Microsoft.JSInterop;

namespace sv_062abbfcada54d83a0cbde9ed28acfb6.Components;

public partial class InfiniteScrollList<TItem> : IAsyncDisposable
{
    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = [];

    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    [Parameter]
    public bool HasMore { get; set; }

    [Parameter, EditorRequired]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    /// <summary>CSS max-height for the scrollable container (default 80vh).</summary>
    [Parameter]
    public string MaxHeight { get; set; } = "80vh";

    /// <summary>
    /// How far from the bottom (in pixels) to trigger loading.
    /// Maps to the IntersectionObserver rootMargin bottom value.
    /// </summary>
    [Parameter]
    public int LoadThreshold { get; set; } = 200;

    [Inject] private IJSRuntime JS { get; set; } = default!;

    private ElementReference _sentinelRef;
    private IJSObjectReference? _module;
    private DotNetObjectReference<InfiniteScrollList<TItem>>? _dotNetRef;
    private bool _isLoading;
    private bool _observerAttached;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./_content/sv-062abbfcada54d83a0cbde9ed28acfb6/js/infinite-scroll.js");
            _dotNetRef = DotNetObjectReference.Create(this);
        }

        if (HasMore && !_observerAttached && _module is not null)
        {
            await _module.InvokeVoidAsync("observe", _sentinelRef, _dotNetRef, LoadThreshold);
            _observerAttached = true;
        }
    }

    [JSInvokable]
    public async Task OnSentinelVisible()
    {
        if (_isLoading || !HasMore)
            return;

        _isLoading = true;
        StateHasChanged();

        await OnLoadMore.InvokeAsync();

        _isLoading = false;
        _observerAttached = false; // sentinel element is re-created after new items render
        StateHasChanged();
    }

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            await _module.InvokeVoidAsync("disconnect");
            await _module.DisposeAsync();
        }

        _dotNetRef?.Dispose();
    }
}

let observer = null;

export function observe(sentinel, dotNetRef, thresholdPx) {
    disconnect();

    observer = new IntersectionObserver(
        (entries) => {
            if (entries.some(e => e.isIntersecting)) {
                dotNetRef.invokeMethodAsync('OnSentinelVisible');
            }
        },
        {
            root: sentinel.closest('.infinite-scroll-container'),
            rootMargin: `0px 0px ${thresholdPx}px 0px`,
        }
    );

    observer.observe(sentinel);
}

export function disconnect() {
    if (observer) {
        observer.disconnect();
        observer = null;
    }
}

